const event = $('Execute Workflow Trigger').item.json;
const row = $json || {};
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr = v => Array.isArray(v) ? v : [];
const kpis = safeObj(row.kpis);
const github = safeObj(row.github);
const hitos = safeArr(row.hitos_proximos);
const fases = safeObj(row.fases);
const progreso = Number(row.progreso_pct || 0);
const completadas = Number(row.total_completadas || 0);
const total = Number(row.total_tarjetas || 0);
const severidad = String(row.severidad_max || 'baja');
const iaContext = String(row.recomendaciones_ia || '').slice(0, 600);
const diasFin = kpis.dias_hasta_fin || '?';
const proyeccion = kpis.proyeccion || 'sin datos';
const velocidad = kpis.velocidad_tareas_por_dia || 0;
const fechaStr = row.fecha ? new Date(row.fecha).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil' }) : 'desconocida';
const fasesRes = Object.values(fases).map(f => `${f.nombre || 'Fase'}: ${f.pct || 0}%`).join(', ') || 'Sin datos';
const hitosRes = hitos.slice(0, 3).map(h => `${h.nombre} (en ${h.dias_faltan}d)`).join(', ') || 'Sin hitos';
const ciBack = github.ci_back ? github.ci_back.status : 'sin datos';
const ciFront = github.ci_front ? github.ci_front.status : 'sin datos';
const prompt = `Eres el Stakeholder Liaison del proyecto PetSafe (clinica veterinaria, software de gestion). Habla en lenguaje de NEGOCIO: sin commits, PRs, branches, CI/CD, merge, backend, frontend, refactor.\n\nFecha: ${fechaStr} | Fecha limite: 10 jun 2026 | Dias restantes: ${diasFin}\nAvance: ${progreso}% (${completadas}/${total} funcionalidades) | Ritmo: ${velocidad}/dia | Alerta: ${severidad}\nProyeccion: ${proyeccion}\nAreas: ${fasesRes}\nHitos proximos: ${hitosRes}\nCalidad: Produccion backend ${ciBack}, frontend ${ciFront}\nAnalisis PM: ${iaContext}\n\nEscribe un resumen ejecutivo para el cliente/sponsor. Texto plano, SIN markdown, SIN asteriscos. Maximo 200 palabras.\nSecciones obligatorias:\nESTADO: Una oracion de estado y porcentaje.\nLOGROS: Que puede hacer el usuario final hoy.\nPROXIMOS PASOS: Que valor se entrega esta semana.\nRIESGOS: Si hay riesgo para la fecha o calidad (lenguaje de negocio).`;
return [{ json: { correlation_id: event.correlation_id || `stakeholder-${Date.now()}`, event_type: event.event_type || 'stakeholder_report', actor: event.actor || 'system', prompt, progreso, severidad, diasFin, proyeccion, fechaStr } }];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const summary = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Prepare Stakeholder Context').item.json;
const colorMap = { alta: 15158332, media: 16761095, baja: 3066993 };
const color = colorMap[ctx.severidad] || 3066993;
const semE = ctx.severidad === 'alta' ? '🔴' : ctx.severidad === 'media' ? '🟡' : '🟢';
const discord_payload = { username: 'PM PetSafe · Liaison', embeds: [{ title: `${semE} Resumen Ejecutivo PetSafe · ${ctx.fechaStr}`, description: summary.slice(0, 3900), color, fields: [{ name: '📊 Avance Global', value: `**${ctx.progreso}%** · ${ctx.diasFin}d hasta entrega`, inline: true }, { name: '📈 Proyección', value: String(ctx.proyeccion), inline: true }], footer: { text: 'Reporte ejecutivo · PM PetSafe AI' }, timestamp: new Date().toISOString() }], allowed_mentions: { parse: [] } };
return [{ json: { correlation_id: ctx.correlation_id, agent_role: 'Stakeholder Liaison', decision_type: 'stakeholder_report', input_summary: `Stakeholder report: ${ctx.progreso}% progress, severity=${ctx.severidad}`.slice(0,500), context_used: { progreso: ctx.progreso, severidad: ctx.severidad, diasFin: ctx.diasFin }, evidence: { executive_summary: summary.slice(0,1000) }, decision: { summary: summary.slice(0,500) }, recommendation: summary.slice(0,500), confidence: 0.9, risk_level: ctx.severidad === 'alta' ? 'high' : ctx.severidad === 'media' ? 'medium' : 'low', requires_human_approval: false, discord_payload } }];
